        r['Amount'] = int(r['Amount'])
    except:
        try:
            r['Amount'] = int(float(r['Amount']))
        except:
            r['Amount'] = 0

# load civic park-related completed-in-2022 project names from previous result
park_projects = var_call_38i97AxeFe4LtdSqT17QEvSZ
